mapper.select:
SELECT COUNT(*) 
FROM User_Coupon 
WHERE user_id = #{userId} 
  AND coupon_code = #{couponCode}

SELECT COUNT(*)
FROM pass_usage_log
WHERE user_id = #{userId}
AND review_no = #{reviewNo}

SELECT COUNT(*)
FROM pass_usage_log PUL
JOIN review R ON PUL.review_no = R.review_no
WHERE PUL.user_id = #{userId}
AND R.is_paid = 1
AND R.user_id != #{userId}

SELECT COUNT(*)
FROM free_view_log FVL
JOIN review R ON FVL.review_no = R.review_no
WHERE FVL.user_id = #{userId}
AND R.is_paid = 0
AND R.user_id != #{userId}

SELECT COUNT(*)
FROM review
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM company_like
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM post_like PL
JOIN community_post CP ON PL.post_no = CP.post_no
WHERE PL.user_id = #{userId}
AND CP.user_id != #{userId}

SELECT COUNT(*)
FROM review_like RL
JOIN review R ON RL.review_no = R.review_no
WHERE RL.user_id = #{userId}
AND R.user_id != #{userId}

