mapper.select:
SELECT COM_NAME
FROM COMPANY
WHERE USER_ID = #{userId}

SELECT M.user_id 
FROM member M
JOIN user_detail UD ON M.user_id = UD.user_id
WHERE UD.name = #{userName} 
  AND REPLACE(M.tel, '-', '') = #{userTel}

UNION

SELECT M.user_id 
FROM member M
JOIN company C ON M.user_id = C.user_id
WHERE C.ceo_name = #{userName} 
  AND REPLACE(M.tel, '-', '') = #{userTel}

SELECT COUNT(*) FROM (
    SELECT M.user_id 
    FROM member M
    JOIN user_detail UD ON M.user_id = UD.user_id
    WHERE M.user_id = #{userId} 
      AND UD.name = #{userName} 
      AND REPLACE(M.tel, '-', '') = #{userTel}

    UNION

    SELECT M.user_id 
    FROM member M
    JOIN company C ON M.user_id = C.user_id
    WHERE M.user_id = #{userId} 
      AND C.ceo_name = #{userName} 
      AND REPLACE(M.tel, '-', '') = #{userTel}
) AS combined_user

